from flask import Flask, request, jsonify
from flask_login import login_required, current_user

app = Flask(__name__)

@app.route('/update_profile', methods=['PUT'])
@login_required
def update_profile():
    data = request.json
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']
    updated_fields = {}

    for field in allowed_fields:
        if field in data:
            updated_fields[field] = data[field]

    if not updated_fields:
        return jsonify({"error": "No valid fields to update"}), 400

    for key, value in updated_fields.items():
        setattr(current_user, key, value)

    # Assuming the current_user object has a save or commit method to persist changes
    current_user.save()

    return jsonify({"success": True, "updated_fields": updated_fields}), 200

if __name__ == "__main__":
    app.run(debug=True)